// Flatten the bot payload. n8n's Webhook node nests the POST body under
// `body`; fall back to the root for manual test executions.
const b = $input.first().json.body ?? $input.first().json;

return [
  {
    json: {
      userId: b.userId ?? '',
      userName: b.userName ?? '',
      message: b.message ?? '',
      channelId: b.channelId ?? '',
      channelName: b.channelName ?? '',
      serverId: b.serverId ?? '',
      recentWarnings: Array.isArray(b.recentWarnings) ? b.recentWarnings : [],
      serverRules: b.serverRules ?? '',
      mode: b.mode ?? 'moderate',
      timestamp: b.timestamp ?? new Date().toISOString(),
    },
  },
];

